const matches = $input.item.json.matches || [];
const question = $input.item.json.question;
const contextBlock = matches
  .map((m, i) => `[Source ${i+1}: ${m.metadata.source}]\n${m.metadata.text}`)
  .join('\n\n---\n\n');
const sources = matches.map(m => `${m.metadata.source} (chunk ${m.metadata.chunk_index})`);
return [{ json: { question, contextBlock, sources } }];
